// order-header.service.ts - VERSIONE SEMPLIFICATA E FUNZIONANTE
import { inject, Injectable } from '@angular/core';
import { BaseService } from '../Base/base.service';
import { OrderHeader } from '../../models';
import { OrderHelperService } from './order-helper.service';

@Injectable({ providedIn: 'root' })
export class OrderHeaderService extends BaseService<OrderHeader> {
  protected override getTableName(): string {
    return 'order_headers';
  }

  protected hasRestaurantId(): boolean { return true; }

  // 🆕 Crea tavolata per tavolo
  async createForTable(tableId: string, customerName?: string): Promise<OrderHeader | null> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) {
        console.error('❌ Restaurant ID non trovato');
        return null;
      }

      const orderNumber = await this.generateOrderNumber();

      const newHeader: Partial<OrderHeader> = {
        restaurant_id: restaurantId,
        table_id: tableId,
        order_number: orderNumber,
        status: 'active',
        customer_name: customerName || 'Cliente',
        total_amount: 0,
      };

      console.log('📤 Creazione OrderHeader (tavolata):', newHeader);
      
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .insert(newHeader)
        .select()
        .single();

      if (error) {
        console.error('❌ Errore creazione order header:', error);
        return null;
      }

      return data as OrderHeader;
    } catch (error: any) {
      console.error('❌ Errore creazione order header:', error);
      return null;
    }
  }

  // 🔢 Genera numero ordine univoco
  private async generateOrderNumber(): Promise<string> {
    const date = new Date();
    const year = date.getFullYear().toString().slice(-2);
    const month = (date.getMonth() + 1).toString().padStart(2, '0');
    const day = date.getDate().toString().padStart(2, '0');
    const random = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
    return `TAV-${year}${month}${day}-${random}`;
  }

  // 📊 Ottiene OrderHeader attivo per un tavolo (SENZA JOIN COMPLESSI)
async getActiveByTable(tableId: string): Promise<OrderHeader | null> {
  try {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return null;

    // Query più robusta senza .single() per evitare errori 406
    const { data, error } = await this.supabaseService
      .getSupabaseClient()
      .from('order_headers')
      .select('*')
      .eq('restaurant_id', restaurantId)
      .eq('table_id', tableId)
      .in('status', ['active', 'open', 'pending']) // Supporta più stati
      .order('created_at', { ascending: false })
      .limit(1);

    if (error) {
      console.error('❌ Errore query order_headers:', error);
      return null;
    }

    return data && data.length > 0 ? (data[0] as OrderHeader) : null;
  } catch (error) {
    console.error('❌ Errore getActiveByTable:', error);
    return null;
  }
}

  // 🆕 Chiudi tavolata
  async closeTavolata(orderHeaderId: string): Promise<boolean> {
    return await this.update(orderHeaderId, { 
      status: 'completed',
      updated_at: new Date().toISOString()
    });
  }

  // 🆕 Get by ID semplice (versione async)
async getByIdAsync(id: string): Promise<OrderHeader | null> {
  try {
    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from(this.getTableName())
      .select('*')
      .eq('id', id)
      .single();

    if (error) throw error;
    return data as OrderHeader;
  } catch (error) {
    console.error('Errore getById:', error);
    return null;
  }
}

// 🆕 Chiudi tutti gli order headers attivi per un tavolo
async closeAllActiveHeadersForTable(tableId: string): Promise<boolean> {
  try {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return false;

    const { error } = await this.supabaseService
      .getSupabaseClient()
      .from(this.getTableName())
      .update({ 
        status: 'completed',
        updated_at: new Date().toISOString()
      })
      .eq('restaurant_id', restaurantId)
      .eq('table_id', tableId)
      .eq('status', 'active');

    return !error;
  } catch (error) {
    console.error('Errore chiusura order headers:', error);
    return false;
  }
}


async closeHeader(headerId: string): Promise<boolean> {
  return await this.update(headerId, { 
    status: 'completed',
    updated_at: new Date().toISOString()
  });
}


// 🆕 Alias per getActiveByTable (per mantenere compatibilità)
async getActiveOrderHeaderByTable(tableId: string): Promise<OrderHeader | null> {
  // Questo è solo un alias per il metodo che già esiste
  return this.getActiveByTable(tableId);
}

// 🆕 Carica order header con dettagli completi
async loadWithDetails(id: string): Promise<OrderHeader | null> {
  try {
    // Usa OrderHelperService per caricare i dettagli completi
    const orderHelper = inject(OrderHelperService); // Oppure passa il servizio nel costruttore
    
    return await orderHelper.loadFullOrder(id);
  } catch (error) {
    console.error('Errore loadWithDetails:', error);
    return null;
  }
}

// 🆕 Conta gli order items per un tavolo
async getTableOrderItemsCount(tableId: string): Promise<number> {
  try {
    // Usa il metodo che abbiamo creato
    const activeHeader = await this.getActiveByTable(tableId);
    if (!activeHeader) return 0;

    // Carica i dettagli
    const orderHelper = inject(OrderHelperService);
    const fullHeader = await orderHelper.loadFullOrder(activeHeader.id);
    
    if (!fullHeader || !fullHeader.comande) return 0;

    let totalItems = 0;
    for (const comanda of fullHeader.comande) {
      if (comanda.order_items) {
        totalItems += comanda.order_items.length;
      }
    }

    return totalItems;

  } catch (error) {
    console.error('Errore getTableOrderItemsCount:', error);
    return 0;
  }
}

}