// comanda.service.ts - VERSIONE CORRETTA CON GESTIONE DRAFT
import { Injectable } from '@angular/core';
import { Comanda, OrderStatus } from '../../models';
import { BaseService } from '../Base/base.service';

@Injectable({ providedIn: 'root' })
export class ComandaService extends BaseService<Comanda> {
  protected override getTableName(): string {
    return 'comande';
  }

  protected hasRestaurantId(): boolean { return true; }

  // 🆕 Crea comanda per order header
  async createForOrderHeader(
    orderHeaderId: string, 
    comandaNumber?: number
  ): Promise<Comanda | null> {
    try {
      // CONTROLLO: Se l'ID è un draft, NON fare query al database
      if (orderHeaderId.startsWith('draft-')) {
        console.error('❌ Tentativo di creare comanda per order header draft:', orderHeaderId);
        console.log('⚠️ Questa operazione dovrebbe essere gestita in locale fino al salvataggio');
        return null;
      }

      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) {
        console.error('❌ Nessun restaurantId');
        return null;
      }

      // 1. Recupera order header
      const { data: orderHeader, error: headerError } = await this.supabaseService.getSupabaseClient()
        .from('order_headers')
        .select('*')
        .eq('id', orderHeaderId)
        .single();

      if (headerError) {
        console.error('❌ Errore recupero order header:', headerError);
        return null;
      }

      if (!orderHeader) {
        console.error('❌ Order header non trovato');
        return null;
      }

      // 2. Calcola numero comanda
      const nextComanda = comandaNumber || await this.getNextComandaNumber(orderHeaderId);
      
      // 3. Order number univoco
      const orderNumber = `CMD-${orderHeader.order_number}-${nextComanda}`;
      
      // 4. Crea comanda
      const newComanda: any = {
        order_number: orderNumber,
        restaurant_id: restaurantId,
        order_header_id: orderHeaderId,
        tavolata_id: orderHeaderId,
        comanda_number: nextComanda,
        table_id: orderHeader.table_id,
        customer_name: orderHeader.customer_name || 'Cliente',
        customer_phone: orderHeader.customer_phone || '',
        status: 'ordered',
        subtotal: 0,
        tax_amount: 0,
        discount_amount: 0,
        total_amount: 0,
        customer_notes: '',
        order_type: 'dine_in'
      };

      console.log('📤 Creazione comanda nel database:', newComanda);

      const { data: comanda, error: insertError } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .insert(newComanda)
        .select()
        .single();

      if (insertError) {
        console.error('❌ Errore creazione comanda:', insertError);
        return null;
      }

      console.log('✅ Comanda creata con successo:', comanda.id);
      return comanda as Comanda;
      
    } catch (error: any) {
      console.error('💥 ERRORE createForOrderHeader:', error);
      return null;
    }
  }

  private async getNextComandaNumber(orderHeaderId: string): Promise<number> {
    try {
      // Se è un draft, restituisci 1
      if (orderHeaderId.startsWith('draft-')) {
        return 1;
      }

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('comanda_number')
        .eq('order_header_id', orderHeaderId)
        .order('comanda_number', { ascending: false })
        .limit(1);

      if (error) throw error;
      return data && data.length > 0 ? data[0].comanda_number + 1 : 1;
    } catch (error) {
      console.error('Errore calcolo prossima comanda:', error);
      return 1;
    }
  }

  // 📊 Carica comande per order header (tavolata)
  async loadByOrderHeaderId(orderHeaderId: string): Promise<Comanda[]> {
    try {
      // Se è un draft, restituisci array vuoto
      if (orderHeaderId.startsWith('draft-')) {
        console.log('⚠️ Tentativo di caricare comande per draft order header');
        return [];
      }

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('order_header_id', orderHeaderId)
        .order('comanda_number', { ascending: true });

      if (error) throw error;
      return (data || []) as Comanda[];
    } catch (error) {
      console.error('Errore caricamento comande:', error);
      return [];
    }
  }

  async updateStatus(comandaId: string, status: OrderStatus): Promise<boolean> {
    try {
      const { error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .update({ 
          status,
          updated_at: new Date().toISOString()
        })
        .eq('id', comandaId);

      return !error;
    } catch (error) {
      console.error('Errore aggiornamento stato comanda:', error);
      return false;
    }
  }
}