// order-item.service.ts - VERSIONE CORRETTA SENZA total_price nell'insert
import { Injectable } from '@angular/core';
import { OrderItem } from '../../models';
import { BaseService } from '../Base/base.service';

@Injectable({ providedIn: 'root' })
export class OrderItemService extends BaseService<OrderItem> {
  protected override getTableName(): string {
    return 'order_items';
  }

  protected hasRestaurantId(): boolean { return true; }

  // 🆕 Aggiungi piatto a una comanda - SENZA total_price
  async addItemToComanda(
    comandaId: string,
    dishId: string,
    quantity: number = 1,
    unitPrice: number,
    itemNotes: string = ''
  ): Promise<OrderItem | null> {
    try {
      console.log('🔄 OrderItemService.addItemToComanda chiamato', {
        comandaId,
        dishId,
        quantity,
        unitPrice
      });

      // 1. Ottieni restaurant_id
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) {
        console.error('❌ Nessun restaurantId');
        return null;
      }

      // 2. Prepara dati per l'inserimento - SENZA total_price
      const orderItemData: any = {
        order_id: comandaId,      // FK a comande.id
        dish_id: dishId,
        quantity: quantity,
        unit_price: unitPrice,
        // total_price: unitPrice * quantity,  // RIMOSSO - sarà calcolato dal database
        item_notes: itemNotes || '',
        status: 'ordered',
        restaurant_id: restaurantId  // Se la colonna esiste
      };

      console.log('📤 Insert order item con dati (senza total_price):', orderItemData);

      // 3. INSERT senza total_price
      const { data, error } = await this.supabaseService
        .getSupabaseClient()
        .from(this.getTableName())
        .insert(orderItemData)
        .select()  
        .single();

      if (error) {
        console.error('❌ ERRORE INSERT:', {
          message: error.message,
          details: error.details,
          hint: error.hint,
          code: error.code
        });
        return null;
      }

      console.log('✅ Order item inserito:', data);

      // 4. Recupera nome del piatto separatamente
      const dishName = await this.getDishName(dishId);
      
      // 5. Ritorna l'oggetto completo con total_price calcolato localmente per l'UI
      return {
        ...data,
        dish_name: dishName,
        comanda_id: data.order_id,
        total_price: unitPrice * quantity  // Calcolato localmente per l'UI
      } as OrderItem;

    } catch (error: any) {
      console.error('💥 Errore critico:', error);
      return null;
    }
  }

  private async getDishName(dishId: string): Promise<string> {
    try {
      const { data, error } = await this.supabaseService
        .getSupabaseClient()
        .from('dishes')
        .select('name')
        .eq('id', dishId)
        .single();

      if (error || !data) {
        console.warn('⚠️ Impossibile recuperare nome piatto:', error);
        return 'Piatto';
      }

      return data.name;
    } catch (error) {
      console.error('Errore recupero nome piatto:', error);
      return 'Piatto';
    }
  }

  // 📋 Carica piatti per comanda
  async loadByComandaId(comandaId: string): Promise<OrderItem[]> {
    try {
      const { data, error } = await this.supabaseService
        .getSupabaseClient()
        .from('order_items')
        .select(`
          *,
          dish:dish_id(name)
        `)
        .eq('order_id', comandaId)
        .order('created_at', { ascending: true });

      if (error) throw error;

      return (data || []).map(item => ({
        ...item,
        dish_name: item.dish?.name || 'Piatto',
        comanda_id: item.order_id
      })) as OrderItem[];
    } catch (error) {
      console.error('Errore caricamento order_items:', error);
      return [];
    }
  }

  // 🔄 Aggiorna quantità - SENZA aggiornare total_price (sarà calcolato dal DB)
  async updateQuantity(itemId: string, quantity: number): Promise<boolean> {
    try {
      const { error } = await this.supabaseService
        .getSupabaseClient()
        .from(this.getTableName())
        .update({
          quantity,
          updated_at: new Date().toISOString()
          // Non inviare total_price - il DB lo calcolerà
        })
        .eq('id', itemId);

      if (error) throw error;
      return true;

    } catch (error) {
      console.error('Errore aggiornamento quantità:', error);
      return false;
    }
  }

  // Delete() per non usare restaurant_id
  override async delete(itemId: string): Promise<boolean> {
    try {
      const { error } = await this.supabaseService
        .getSupabaseClient()
        .from(this.getTableName())
        .delete()
        .eq('id', itemId);

      if (error) throw error;
      
      const currentData = this.dataSubject.value;
      const updatedData = currentData.filter(item => item.id !== itemId);
      this.dataSubject.next(updatedData);
      
      return true;
    } catch (error: any) {
      console.error('Errore eliminazione order item:', error);
      this.errorSubject.next(error.message);
      return false;
    }
  }

  // 🔄 Aggiorna stato di un item
  async updateItemStatus(itemId: string, status: string): Promise<boolean> {
    try {
      const { error } = await this.supabaseService
        .getSupabaseClient()
        .from(this.getTableName())
        .update({
          status,
          updated_at: new Date().toISOString()
        })
        .eq('id', itemId);

      if (error) throw error;
      return true;

    } catch (error) {
      console.error('Errore aggiornamento stato item:', error);
      return false;
    }
  }

  // 🔄 Aggiorna tutti gli items di una comanda
  async updateAllItemsStatus(comandaId: string, status: string): Promise<boolean> {
    try {
      const items = await this.loadByComandaId(comandaId);
      let allSuccess = true;
      
      for (const item of items) {
        const success = await this.updateItemStatus(item.id, status);
        if (!success) allSuccess = false;
      }
      
      return allSuccess;
    } catch (error) {
      console.error('Errore aggiornamento stati piatti:', error);
      return false;
    }
  }
}