// order-helper.service.ts - VERSIONE CORRETTA
import { Injectable, inject } from '@angular/core';
import { OrderHeaderService } from './order-header.service';
import { ComandaService } from './comanda.service';
import { OrderItemService } from './order-item.service';
import { OrderHeader, Comanda } from '../../models';

@Injectable({ providedIn: 'root' })
export class OrderHelperService {
  private orderHeaderService = inject(OrderHeaderService);
  private comandaService = inject(ComandaService);
  private orderItemService = inject(OrderItemService);

  // 🟢 Occupa tavolo: crea tavolata + prima comanda
  async occupyTable(tableId: string, customerName?: string): Promise<{orderHeader: OrderHeader | null, comanda: Comanda | null}> {
    try {
      // 1. Crea order header (tavolata)
      const orderHeader = await this.orderHeaderService.createForTable(tableId, customerName);
      if (!orderHeader) {
        return { orderHeader: null, comanda: null };
      }

      // 2. Crea prima comanda (numero 1)
      const comanda = await this.comandaService.createForOrderHeader(orderHeader.id, 1);
      
      return { orderHeader, comanda };
    } catch (error) {
      console.error('❌ Errore occupazione tavolo:', error);
      return { orderHeader: null, comanda: null };
    }
  }

  // 🟢 Carica tutta la struttura: order header → comande → order items
  async loadFullOrder(orderHeaderId: string): Promise<OrderHeader | null> {
    try {
      // 1. Carica order header
      const orderHeader = await this.orderHeaderService.getByIdAsync(orderHeaderId);
      if (!orderHeader) return null;

      // 2. Carica comande
      const comande = await this.comandaService.loadByOrderHeaderId(orderHeaderId);
      
      // 3. Per ogni comanda, carica order items
      for (const comanda of comande) {
        const orderItems = await this.orderItemService.loadByComandaId(comanda.id);
        comanda.order_items = orderItems;
      }

      orderHeader.comande = comande;
      return orderHeader;

    } catch (error) {
      console.error('❌ Errore caricamento ordine completo:', error);
      return null;
    }
  }

  // 🟢 Aggiungi piatto (gestisce automaticamente se manca tavolata/comanda)
  async addDishToTable(
    tableId: string,
    dishId: string,
    dishName: string,
    unitPrice: number,
    quantity: number = 1,
    notes: string = ''
  ): Promise<boolean> {
    try {
      // 1. Verifica se esiste tavolata attiva
      let orderHeader = await this.orderHeaderService.getActiveByTable(tableId);
      
      // 2. Se non esiste, crea tavolata e prima comanda
      if (!orderHeader) {
        const result = await this.occupyTable(tableId, 'Cliente');
        if (!result.orderHeader || !result.comanda) return false;
        orderHeader = result.orderHeader;
      }

      // 3. Verifica se esiste comanda attiva (ultima non cancellata)
      let comande = await this.comandaService.loadByOrderHeaderId(orderHeader.id);
      let activeComanda = comande.find(c => c.status !== 'cancelled');
      
      // 4. Se non esiste, crea nuova comanda
      if (!activeComanda) {
        const newComanda = await this.comandaService.createForOrderHeader(orderHeader.id);
        if (!newComanda) return false;
        activeComanda = newComanda;
      }

      // 5. Aggiungi piatto alla comanda
      const orderItem = await this.orderItemService.addItemToComanda(
        activeComanda.id,
        dishId,
        quantity,
        unitPrice,
        notes
      );

      return !!orderItem;

    } catch (error) {
      console.error('❌ Errore aggiunta piatto:', error);
      return false;
    }
  }

  // 🟢 Crea nuova comanda per una tavolata esistente
  async createComandaForOrderHeader(orderHeaderId: string): Promise<Comanda | null> {
    try {
      return await this.comandaService.createForOrderHeader(orderHeaderId);
    } catch (error) {
      console.error('❌ Errore creazione comanda:', error);
      return null;
    }
  }

  // 🟢 Aggiorna quantità di un piatto
  async updateItemQuantity(itemId: string, quantity: number): Promise<boolean> {
    try {
      return await this.orderItemService.updateQuantity(itemId, quantity);
    } catch (error) {
      console.error('❌ Errore aggiornamento quantità:', error);
      return false;
    }
  }

  // 🟢 Rimuovi piatto
  async removeItem(itemId: string): Promise<boolean> {
    try {
      return await this.orderItemService.delete(itemId);
    } catch (error) {
      console.error('❌ Errore rimozione piatto:', error);
      return false;
    }
  }

  // 🟢 Chiudi tavolata
  async closeTavolata(orderHeaderId: string): Promise<boolean> {
    try {
      return await this.orderHeaderService.closeHeader(orderHeaderId);
    } catch (error) {
      console.error('❌ Errore chiusura tavolata:', error);
      return false;
    }
  }

  // 🟢 Aggiorna stato comanda
async updateComandaStatus(comandaId: string, status: string): Promise<boolean> {
  try {
    // Crea un tipo OrderStatus dai valori validi
    type ValidStatus = 'ordered' | 'waiting' | 'preparing' | 'ready' | 'served' | 'cancelled';
    
    // Verifica che lo status sia valido
    const validStatuses: ValidStatus[] = ['ordered', 'waiting', 'preparing', 'ready', 'served', 'cancelled'];
    if (!validStatuses.includes(status as ValidStatus)) {
      console.error('❌ Stato non valido:', status);
      return false;
    }
    
    // Usa direttamente il metodo update del BaseService
    return await this.comandaService.update(comandaId, { 
      status: status as ValidStatus,
      updated_at: new Date().toISOString()
    });
  } catch (error) {
    console.error('❌ Errore aggiornamento stato comanda:', error);
    return false;
  }
}

  
}